INSERT INTO `grammar_lessons` VALUES (1,'Present Simple','present-simple','tense','beginner','<h3>Cấu trúc</h3><p><strong>S + V(s/es)</strong> dùng cho câu khẳng định. Với phủ định dùng <strong>S + do/does not + V</strong>, câu hỏi dùng <strong>Do/Does + S + V?</strong>.</p><h3>Cách dùng</h3><ul><li>Diễn tả thói quen hoặc hành động lặp lại hằng ngày.</li><li>Diễn tả sự thật hiển nhiên, lịch trình cố định.</li><li>Dùng với always, usually, often, sometimes, every day.</li></ul>','I play football every Sunday.\nShe doesn\'t like coffee.\nDo you speak English?',1,'2026-03-27 12:09:53'),(2,'Present Continuous','present-continuous','tense','beginner','<h3>Cấu trúc</h3><p><strong>S + am/is/are + V-ing</strong>.</p><h3>Cách dùng</h3><ul><li>Diễn tả hành động đang xảy ra tại thời điểm nói.</li><li>Nói về kế hoạch gần trong tương lai.</li><li>Dùng với now, right now, at the moment, currently.</li></ul>','She is reading a book right now.\nThey are not playing football.\nAre you listening to me?',2,'2026-03-27 12:09:53'),(3,'Present Perfect','present-perfect','tense','intermediate','<h3>Cấu trúc</h3><p><strong>S + have/has + V3</strong>.</p><h3>Cách dùng</h3><ul><li>Nói về kinh nghiệm đã từng có.</li><li>Diễn tả hành động vừa hoàn thành hoặc còn liên quan hiện tại.</li><li>Dùng với since, for, already, yet, just, ever, never.</li></ul>','I have never seen snow.\nHe has already eaten lunch.\nHave you ever been to Japan?',3,'2026-03-27 12:09:53'),(4,'Past Simple','past-simple','tense','beginner','<h3>Cấu trúc</h3><p><strong>S + V2/ed</strong>. Câu phủ định dùng <strong>did not + V</strong>, câu hỏi dùng <strong>Did + S + V?</strong>.</p><h3>Cách dùng</h3><ul><li>Diễn tả hành động đã xảy ra và kết thúc trong quá khứ.</li><li>Dùng với yesterday, last week, ago, in 2020.</li></ul>','They played tennis last weekend.\nShe didn\'t go to the party.\nDid you see the movie?',4,'2026-03-27 12:09:53'),(5,'Prepositions of Time','prepositions-time','preposition','beginner','<h3>Prepositions of Time</h3><ul><li><strong>At</strong>: dùng với giờ cụ thể, at 7 o’clock, at night.</li><li><strong>On</strong>: dùng với ngày, on Monday, on June 6.</li><li><strong>In</strong>: dùng với tháng, năm, mùa, in March, in 2026.</li></ul>','I wake up at 7 AM.\nThe meeting is on Friday.\nShe was born in 1995.',5,'2026-03-27 12:09:53'),(6,'Modal Verbs','modal-verbs','modal','intermediate','<h3>Modal Verbs</h3><p>Động từ khuyết thiếu đi với động từ nguyên mẫu không “to”.</p><ul><li><strong>Can/Could</strong>: khả năng hoặc lời đề nghị.</li><li><strong>Should</strong>: lời khuyên.</li><li><strong>Must/Have to</strong>: sự bắt buộc.</li><li><strong>May/Might</strong>: khả năng xảy ra.</li></ul>','Can you speak French?\nYou should see a doctor.\nStudents must not use phones in class.',6,'2026-03-27 12:09:53'),(7,'Future Simple (Will)','future-simple','tense','beginner','<h3>Cấu trúc</h3><p><strong>S + will + V</strong>.</p><h3>Cách dùng</h3><ul><li>Dự đoán hoặc quyết định tại thời điểm nói.</li><li>Đưa ra lời hứa, lời đề nghị hoặc lời cảnh báo.</li><li>Dùng với tomorrow, next week, soon, in the future.</li></ul>','I will call you later.\nShe won\'t come to the party.\nWill they finish on time?',7,'2026-03-28 10:50:50'),(8,'Conditional Sentences','conditional-sentences','clause','intermediate','<h3>Conditional Sentences</h3><ul><li><strong>Type 0</strong>: sự thật hiển nhiên. If + present simple, present simple.</li><li><strong>Type 1</strong>: điều kiện có thể xảy ra. If + present simple, will + V.</li><li><strong>Type 2</strong>: giả định hiện tại. If + past simple, would + V.</li></ul>','If you study hard, you will pass the exam.\nIf I had a car, I would drive to work.\nIf water reaches 0??C, it freezes.',8,'2026-03-28 10:50:50'),(9,'Articles (A, An, The)','articles','article','beginner','<h3>Articles</h3><ul><li><strong>A</strong>: đứng trước danh từ số ít bắt đầu bằng phụ âm.</li><li><strong>An</strong>: đứng trước danh từ số ít bắt đầu bằng nguyên âm.</li><li><strong>The</strong>: dùng khi người nghe đã biết đối tượng được nhắc đến hoặc đối tượng là duy nhất.</li></ul>','I read a book yesterday. The book was very interesting.\nShe is an engineer.\nThe Earth goes around the Sun.',9,'2026-03-28 10:50:50'),(10,'Passive Voice','passive-voice','other','intermediate','<h3>Passive Voice</h3><p>Câu bị động nhấn mạnh đối tượng chịu tác động của hành động.</p><p><strong>S + be + V3/ed + by + object</strong>.</p><ul><li>Present simple: The lesson is taught every day.</li><li>Past simple: The book was written in 2020.</li><li>Future simple: The result will be announced tomorrow.</li></ul>','English is spoken worldwide.\nThe cake was made by my mother.\nThe homework has been submitted.',10,'2026-03-28 10:50:50');
/*!40000 ALTER TABLE `grammar_lessons` ENABLE KEYS */;
UNLOCK TABLES;

