INSERT INTO `grammar_questions` VALUES (1,1,'She ___ to school every day.','{\"A\":\"go\",\"B\":\"goes\",\"C\":\"going\",\"D\":\"went\"}','B','Chủ ngữ \"She\" (ngôi 3 số ít) → V thêm s/es'),(2,1,'___ you like coffee?','{\"A\":\"Does\",\"B\":\"Do\",\"C\":\"Is\",\"D\":\"Are\"}','B','\"You\" dùng trợ động từ \"Do\"'),(3,2,'Look! The children ___ in the park.','{\"A\":\"play\",\"B\":\"plays\",\"C\":\"are playing\",\"D\":\"played\"}','C','\"Look!\" → hành động đang xảy ra → Present Continuous'),(4,2,'She ___ a letter right now.','{\"A\":\"writes\",\"B\":\"is writing\",\"C\":\"wrote\",\"D\":\"has written\"}','B','\"right now\" → Present Continuous'),(5,3,'I ___ to Paris three times.','{\"A\":\"go\",\"B\":\"went\",\"C\":\"have been\",\"D\":\"am going\"}','C','Kinh nghiệm → Present Perfect'),(6,3,'She ___ here since 2015.','{\"A\":\"lives\",\"B\":\"lived\",\"C\":\"has lived\",\"D\":\"is living\"}','C','\"since 2015\" → Present Perfect'),(7,4,'They ___ football yesterday.','{\"A\":\"play\",\"B\":\"plays\",\"C\":\"played\",\"D\":\"have played\"}','C','\"yesterday\" → Past Simple'),(8,5,'The class starts ___ 8 AM.','{\"A\":\"in\",\"B\":\"on\",\"C\":\"at\",\"D\":\"by\"}','C','Giờ cụ thể → at'),(9,5,'We go swimming ___ summer.','{\"A\":\"in\",\"B\":\"on\",\"C\":\"at\",\"D\":\"by\"}','A','Mùa → in'),(10,6,'You ___ wear a helmet when cycling.','{\"A\":\"can\",\"B\":\"may\",\"C\":\"should\",\"D\":\"might\"}','C','Lời khuyên → should'),(11,7,'I think it ___ rain tomorrow.','{\"A\":\"rains\",\"B\":\"will rain\",\"C\":\"is raining\",\"D\":\"rained\"}','B','\"I think\" + tương lai → will + V'),(12,7,'I ___ you with your homework tonight.','{\"A\":\"help\",\"B\":\"helped\",\"C\":\"will help\",\"D\":\"helping\"}','C','Quyết định tức thì → will + V'),(13,8,'If she studies hard, she ___ the exam.','{\"A\":\"passes\",\"B\":\"will pass\",\"C\":\"passed\",\"D\":\"would pass\"}','B','Điều kiện loại 1: If + present, will + V'),(14,8,'If I ___ rich, I would buy a house.','{\"A\":\"am\",\"B\":\"was\",\"C\":\"were\",\"D\":\"will be\"}','C','Điều kiện loại 2: If + were/V2, would + V'),(15,9,'She is ___ engineer.','{\"A\":\"a\",\"B\":\"an\",\"C\":\"the\",\"D\":\"(nothing)\"}','B','Trước nguyên âm → \"an\"'),(16,9,'I saw ___ cat in the garden. ___ cat was black.','{\"A\":\"a / The\",\"B\":\"the / A\",\"C\":\"a / A\",\"D\":\"the / The\"}','A','Lần đầu → a, lần sau → the'),(17,10,'English ___ all over the world.','{\"A\":\"speaks\",\"B\":\"is spoken\",\"C\":\"is speaking\",\"D\":\"spoke\"}','B','Bị động present: is/are + V3'),(18,10,'The letter ___ by Tom yesterday.','{\"A\":\"writes\",\"B\":\"written\",\"C\":\"was written\",\"D\":\"is written\"}','C','Bị động past: was/were + V3');
/*!40000 ALTER TABLE `grammar_questions` ENABLE KEYS */;
UNLOCK TABLES;

