INSERT INTO `lesson_contents` VALUES (1,1,'text','<h3>Common Greetings</h3><ul><li><strong>Hello / Hi</strong> - Chao</li><li><strong>Good morning</strong> - Chao buoi sang</li><li><strong>Good afternoon</strong> - Chao buoi chieu</li><li><strong>How are you?</strong> - Ban khoe khong?</li><li><strong>Nice to meet you</strong> - Rat vui duoc gap ban</li></ul>',1),(2,1,'text','<h3>Introducing Yourself</h3><div class=\"dialogue\"><p><strong>A:</strong> Hi! My name is John. What is your name?</p><p><strong>B:</strong> Hello John! I am Sarah. Nice to meet you!</p><p><strong>A:</strong> Nice to meet you too! Where are you from?</p><p><strong>B:</strong> I am from Vietnam. How about you?</p></div>',2),(3,2,'text','<h3>Describing Your Daily Routine</h3><ul><li>I <strong>wake up</strong> at 6:00 AM every day.</li><li>I <strong>have breakfast</strong> at 7:00 AM.</li><li>I <strong>go to work</strong> by bus.</li><li>I <strong>have lunch</strong> at noon.</li><li>I <strong>get home</strong> at 6:00 PM.</li></ul>',1),(4,4,'text','<h3>Ordering Food</h3><div class=\"dialogue\"><p><strong>Waiter:</strong> Good evening! Welcome to our restaurant. Are you ready to order?</p><p><strong>Customer:</strong> Yes, I would like the grilled chicken with salad, please.</p><p><strong>Waiter:</strong> Would you like something to drink?</p><p><strong>Customer:</strong> I will have a glass of orange juice.</p><p><strong>Waiter:</strong> Excellent choice! Your food will be ready in about 15 minutes.</p></div>',1),(5,4,'text','<h3>Useful Phrases at a Restaurant</h3><ul><li><strong>Could I see the menu, please?</strong> - Cho toi xem thuc don</li><li><strong>What do you recommend?</strong> - Ban goi y mon gi?</li><li><strong>I am allergic to...</strong> - Toi bi di ung voi...</li><li><strong>Could I have the bill, please?</strong> - Cho toi tinh tien</li><li><strong>Keep the change</strong> - Khong can thoi lai</li></ul>',2),(6,7,'text','<h3>School Subjects</h3><ul><li><strong>Mathematics</strong> - Toan hoc</li><li><strong>Physics</strong> - Vat ly</li><li><strong>Chemistry</strong> - Hoa hoc</li><li><strong>Biology</strong> - Sinh hoc</li><li><strong>Literature</strong> - Van hoc</li><li><strong>History</strong> - Lich su</li><li><strong>Geography</strong> - Dia ly</li><li><strong>Physical Education (PE)</strong> - The duc</li></ul>',1),(7,7,'text','<h3>Talking About School</h3><div class=\"dialogue\"><p><strong>A:</strong> What is your favorite subject?</p><p><strong>B:</strong> I love Mathematics. I think it is very interesting.</p><p><strong>A:</strong> How many classes do you have today?</p><p><strong>B:</strong> I have five classes. My schedule is quite busy.</p></div>',2),(8,10,'text','<h3>Computer Components</h3><ul><li><strong>CPU (Central Processing Unit)</strong> - Bo xu ly trung tam</li><li><strong>RAM (Random Access Memory)</strong> - Bo nho tam</li><li><strong>Hard Drive / SSD</strong> - O cung</li><li><strong>Monitor</strong> - Man hinh</li><li><strong>Keyboard</strong> - Ban phim</li><li><strong>Mouse</strong> - Chuot</li></ul>',1),(9,10,'text','<h3>Common Computer Actions</h3><ul><li><strong>Click</strong> - Nhan chuot</li><li><strong>Double-click</strong> - Nhan doi</li><li><strong>Drag and drop</strong> - Keo va tha</li><li><strong>Copy and paste</strong> - Sao chep va dan</li><li><strong>Download / Upload</strong> - Tai xuong / Tai len</li><li><strong>Install / Uninstall</strong> - Cai dat / Go cai dat</li></ul>',2),(10,13,'text','<h3>At the Doctor Office</h3><div class=\"dialogue\"><p><strong>Doctor:</strong> Good morning! What brings you here today?</p><p><strong>Patient:</strong> I have had a headache and a sore throat for three days.</p><p><strong>Doctor:</strong> Let me check your temperature. Do you have any other symptoms?</p><p><strong>Patient:</strong> I also feel tired and have a runny nose.</p><p><strong>Doctor:</strong> It sounds like you have the flu. I will prescribe some medicine for you.</p></div>',1),(11,13,'text','<h3>Common Health Vocabulary</h3><ul><li><strong>Headache</strong> - Dau dau</li><li><strong>Stomachache</strong> - Dau bung</li><li><strong>Fever</strong> - Sot</li><li><strong>Cough</strong> - Ho</li><li><strong>Sore throat</strong> - Dau hong</li><li><strong>Runny nose</strong> - So mui</li><li><strong>Medicine / Pill</strong> - Thuoc</li></ul>',2),(12,7,'text','<h3>Useful Phrases at a Restaurant</h3>\n<ul>\n<li><strong>Can I see the menu, please?</strong> - Cho t??i xem th???c ????n ???????c kh??ng?</li>\n<li><strong>I would like to order...</strong> - T??i mu???n g???i...</li>\n<li><strong>What do you recommend?</strong> - B???n g???i ?? m??n g???</li>\n<li><strong>Is this dish spicy?</strong> - M??n n??y c?? cay kh??ng?</li>\n<li><strong>Could I have the bill, please?</strong> - Cho t??i t??nh ti???n ???????c kh??ng?</li>\n<li><strong>I\'m allergic to...</strong> - T??i b??? d??? ???ng v???i...</li>\n</ul>',1),(13,7,'text','<h3>Sample Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Waiter:</strong> Good evening! Welcome to our restaurant. A table for two?</p>\n<p><strong>You:</strong> Yes, please. Could I see the menu?</p>\n<p><strong>Waiter:</strong> Of course. Here you go. Would you like something to drink?</p>\n<p><strong>You:</strong> I\'ll have an orange juice, please.</p>\n<p><strong>Waiter:</strong> Are you ready to order?</p>\n<p><strong>You:</strong> Yes, I\'d like the grilled chicken with salad, please.</p>\n<p><strong>Waiter:</strong> Excellent choice! Anything else?</p>\n<p><strong>You:</strong> No, that\'s all. Thank you!</p>\n</div>',2),(14,8,'text','<h3>Ph????ng ph??p n???u ??n (Cooking Methods)</h3>\n<ul>\n<li><strong>Boil</strong> (lu???c): Cook food in boiling water - <em>Boil the eggs for 10 minutes.</em></li>\n<li><strong>Fry</strong> (chi??n): Cook in oil - <em>Fry the fish until golden brown.</em></li>\n<li><strong>Grill</strong> (n?????ng): Cook over direct heat - <em>Grill the steak for 5 minutes each side.</em></li>\n<li><strong>Steam</strong> (h???p): Cook with steam - <em>Steam the vegetables for 8 minutes.</em></li>\n<li><strong>Bake</strong> (n?????ng l??): Cook in an oven - <em>Bake the cake at 180??C for 30 minutes.</em></li>\n<li><strong>Stir-fry</strong> (x??o): Cook quickly in a wok - <em>Stir-fry the noodles with soy sauce.</em></li>\n<li><strong>Roast</strong> (quay): Cook in oven with oil - <em>Roast the chicken with herbs.</em></li>\n</ul>',1),(15,8,'text','<h3>C??c d???ng c??? nh?? b???p (Kitchen Utensils)</h3>\n<ul>\n<li><strong>Knife</strong> /na??f/ - dao</li>\n<li><strong>Cutting board</strong> - th???t</li>\n<li><strong>Frying pan</strong> - ch???o</li>\n<li><strong>Pot</strong> - n???i</li>\n<li><strong>Oven</strong> - l?? n?????ng</li>\n<li><strong>Spatula</strong> - th??a x??c</li>\n<li><strong>Whisk</strong> - ph???i ????nh tr???ng</li>\n<li><strong>Ladle</strong> - mu??i m??c canh</li>\n</ul>',2),(16,9,'text','<h3>University Vocabulary</h3>\n<ul>\n<li><strong>Major</strong> - chuy??n ng??nh: <em>My major is Computer Science.</em></li>\n<li><strong>GPA (Grade Point Average)</strong> - ??i???m trung b??nh: <em>She has a GPA of 3.8.</em></li>\n<li><strong>Deadline</strong> - h???n n???p: <em>The deadline for the paper is next Friday.</em></li>\n<li><strong>Thesis</strong> - lu???n v??n: <em>He is writing his graduation thesis.</em></li>\n<li><strong>Campus</strong> - khu??n vi??n tr?????ng: <em>The campus has a beautiful library.</em></li>\n<li><strong>Semester</strong> - h???c k???: <em>This semester I am taking 5 courses.</em></li>\n</ul>',1),(17,9,'text','<h3>Dialogue: Registering for Classes</h3>\n<div class=\"dialogue\">\n<p><strong>Student:</strong> Excuse me, I\'d like to register for the English Communication class.</p>\n<p><strong>Advisor:</strong> Sure. That class meets on Mondays and Wednesdays. Is that okay with your schedule?</p>\n<p><strong>Student:</strong> Yes, that works. How many credits is it?</p>\n<p><strong>Advisor:</strong> It\'s 3 credits. You also need to complete a prerequisite first.</p>\n<p><strong>Student:</strong> What prerequisite is required?</p>\n<p><strong>Advisor:</strong> English Fundamentals. Have you completed that?</p>\n<p><strong>Student:</strong> Yes, I finished it last semester.</p>\n<p><strong>Advisor:</strong> Great! You\'re all set then.</p>\n</div>',2),(18,10,'text','<h3>Useful Classroom Phrases</h3>\n<h4>Asking Questions</h4>\n<ul>\n<li><strong>Could you repeat that, please?</strong> - B???n c?? th??? nh???c l???i ???????c kh??ng?</li>\n<li><strong>What does this word mean?</strong> - T??? n??y ngh??a l?? g???</li>\n<li><strong>How do you spell that?</strong> - T??? ???? vi???t th??? n??o?</li>\n<li><strong>Can you explain it in a simpler way?</strong> - Gi???i th??ch ????n gi???n h??n ???????c kh??ng?</li>\n</ul>\n<h4>Participating in Class</h4>\n<ul>\n<li><strong>I agree with...</strong> - T??i ?????ng ?? v???i...</li>\n<li><strong>In my opinion...</strong> - Theo ?? ki???n t??i...</li>\n<li><strong>Could I add something?</strong> - T??i c?? th??? b??? sung ???????c kh??ng?</li>\n<li><strong>I\'m not sure I understand.</strong> - T??i kh??ng ch???c l?? t??i hi???u.</li>\n</ul>',1),(19,12,'text','<h3>Essential Computer Terms</h3>\n<ul>\n<li><strong>Operating System (OS)</strong> - h??? ??i???u h??nh: Windows, macOS, Linux</li>\n<li><strong>RAM (Random Access Memory)</strong> - b??? nh??? t???m th???i</li>\n<li><strong>Hard Drive / SSD</strong> - ??? c???ng / ??? th??? r???n</li>\n<li><strong>Processor (CPU)</strong> - b??? x??? l??</li>\n<li><strong>Monitor</strong> - m??n h??nh</li>\n<li><strong>Keyboard</strong> - b??n ph??m</li>\n<li><strong>Mouse</strong> - chu???t</li>\n<li><strong>USB Port</strong> - c???ng USB</li>\n</ul>\n<h3>Common Actions</h3>\n<ul>\n<li><strong>Install</strong> - c??i ?????t: <em>Install the latest version of the software.</em></li>\n<li><strong>Update</strong> - c???p nh???t: <em>Please update your browser.</em></li>\n<li><strong>Restart</strong> - kh???i ?????ng l???i: <em>Try restarting your computer.</em></li>\n<li><strong>Back up</strong> - sao l??u: <em>Always back up your files.</em></li>\n</ul>',1),(20,15,'text','<h3>At the Doctor\'s Office</h3>\n<h4>Describing Symptoms</h4>\n<ul>\n<li><strong>I have a headache.</strong> - T??i b??? ??au ?????u.</li>\n<li><strong>I have a sore throat.</strong> - T??i b??? ??au h???ng.</li>\n<li><strong>I feel dizzy.</strong> - T??i c???m th???y ch??ng m???t.</li>\n<li><strong>I have a fever.</strong> - T??i b??? s???t.</li>\n<li><strong>My stomach hurts.</strong> - T??i b??? ??au b???ng.</li>\n<li><strong>I\'ve been coughing a lot.</strong> - T??i b??? ho nhi???u.</li>\n</ul>\n<h4>Dialogue</h4>\n<div class=\"dialogue\">\n<p><strong>Doctor:</strong> What seems to be the problem?</p>\n<p><strong>Patient:</strong> I\'ve had a bad cough and a sore throat for three days.</p>\n<p><strong>Doctor:</strong> Do you have a fever?</p>\n<p><strong>Patient:</strong> Yes, my temperature was 38 degrees last night.</p>\n<p><strong>Doctor:</strong> Let me examine you. Open your mouth, please. I see your throat is red and swollen. I will prescribe some medicine for you.</p>\n<p><strong>Patient:</strong> How often should I take the medicine?</p>\n<p><strong>Doctor:</strong> Take it three times a day after meals. You should also rest and drink plenty of water.</p>\n</div>',1),(21,16,'text','<h3>Exercise Vocabulary</h3>\n<ul>\n<li><strong>Warm up</strong> - kh???i ?????ng: <em>Always warm up before exercising.</em></li>\n<li><strong>Cool down</strong> - th??? l???ng: <em>Cool down with some stretches after your workout.</em></li>\n<li><strong>Push-up</strong> - h??t ?????t</li>\n<li><strong>Sit-up</strong> - g???p b???ng</li>\n<li><strong>Squat</strong> - squat, ng???i x???m</li>\n<li><strong>Plank</strong> - t?? th??? plank</li>\n<li><strong>Treadmill</strong> - m??y ch???y b???</li>\n<li><strong>Dumbbell</strong> - t??? tay</li>\n<li><strong>Cardio</strong> - b??i t???p tim m???ch</li>\n<li><strong>Yoga</strong> - yoga</li>\n</ul>',1),(36,3,'text','<h3>Rooms in a House</h3>\n<ul>\n<li><strong>Living room</strong> (phòng khách) - We usually watch TV in the living room.</li>\n<li><strong>Bedroom</strong> (phòng ngủ) - I have my own bedroom upstairs.</li>\n<li><strong>Kitchen</strong> (nhà bếp) - My mother cooks in the kitchen every day.</li>\n<li><strong>Bathroom</strong> (phòng tắm) - The bathroom is next to my bedroom.</li>\n<li><strong>Dining room</strong> (phòng ăn) - We have dinner together in the dining room.</li>\n<li><strong>Balcony</strong> (ban công) - I like to sit on the balcony and read books.</li>\n<li><strong>Garage</strong> (nhà để xe) - My father parks his car in the garage.</li>\n</ul>',1),(37,3,'text','<h3>Household Chores</h3>\n<ul>\n<li><strong>Do the laundry</strong> - giặt quần áo</li>\n<li><strong>Wash the dishes</strong> - rửa bát</li>\n<li><strong>Sweep the floor</strong> - quét nhà</li>\n<li><strong>Take out the trash</strong> - đổ rác</li>\n<li><strong>Water the plants</strong> - tưới cây</li>\n<li><strong>Make the bed</strong> - dọn giường</li>\n</ul>\n<h3>Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Mom:</strong> Can you help me with the housework today?</p>\n<p><strong>You:</strong> Sure, Mom! What should I do?</p>\n<p><strong>Mom:</strong> Please wash the dishes and sweep the floor.</p>\n<p><strong>You:</strong> OK. Should I also take out the trash?</p>\n<p><strong>Mom:</strong> Yes, please. Thank you for helping!</p>\n</div>',2),(38,5,'text','<h3>Hotel Check-in Vocabulary</h3>\n<ul>\n<li><strong>Reservation</strong> - đặt phòng: <em>I have a reservation under the name Nguyen.</em></li>\n<li><strong>Single room</strong> - phòng đơn</li>\n<li><strong>Double room</strong> - phòng đôi</li>\n<li><strong>Check-in / Check-out</strong> - nhận phòng / trả phòng</li>\n<li><strong>Room key / Key card</strong> - chìa khóa phòng / thẻ từ</li>\n<li><strong>Front desk / Reception</strong> - quầy lễ tân</li>\n<li><strong>Bellboy</strong> - nhân viên khuân hành lý</li>\n</ul>',1),(39,5,'text','<h3>Check-in Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Receptionist:</strong> Good evening! Welcome to Grand Hotel. How can I help you?</p>\n<p><strong>Guest:</strong> Hello! I have a reservation for two nights. The name is Tran Van Minh.</p>\n<p><strong>Receptionist:</strong> Let me check... Yes, I found it. A double room with breakfast included. May I see your ID or passport, please?</p>\n<p><strong>Guest:</strong> Here you are.</p>\n<p><strong>Receptionist:</strong> Thank you. Your room is 504 on the fifth floor. Here is your key card. Breakfast is served from 6:30 to 9:30 AM in the restaurant on the second floor.</p>\n<p><strong>Guest:</strong> Is there Wi-Fi in the room?</p>\n<p><strong>Receptionist:</strong> Yes, the password is on the card in your room. Enjoy your stay!</p>\n</div>',2),(40,6,'text','<h3>Asking for Directions</h3>\n<ul>\n<li><strong>Excuse me, how do I get to...?</strong> - Xin lỗi, tôi đi đến... bằng cách nào?</li>\n<li><strong>Is it far from here?</strong> - Có xa đây không?</li>\n<li><strong>Turn left / Turn right</strong> - Rẽ trái / Rẽ phải</li>\n<li><strong>Go straight</strong> - Đi thẳng</li>\n<li><strong>It\'s on the corner</strong> - Nó ở góc đường</li>\n<li><strong>It\'s next to / opposite / between</strong> - Nó ở bên cạnh / đối diện / giữa</li>\n<li><strong>Take the first/second left</strong> - Rẽ trái ở ngã rẽ đầu tiên/thứ hai</li>\n</ul>',1),(41,6,'text','<h3>Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Tourist:</strong> Excuse me, could you tell me how to get to the nearest bank?</p>\n<p><strong>Local:</strong> Sure! Go straight for about 200 meters, then turn right at the traffic light.</p>\n<p><strong>Tourist:</strong> Turn right at the traffic light. Got it.</p>\n<p><strong>Local:</strong> Then walk past the post office. The bank is on your left, next to a coffee shop.</p>\n<p><strong>Tourist:</strong> How long does it take to walk there?</p>\n<p><strong>Local:</strong> About 5 minutes. You can\'t miss it!</p>\n<p><strong>Tourist:</strong> Thank you so much!</p>\n</div>',2),(42,11,'text','<h3>University Life in English-speaking Countries</h3>\n<p>University life in English-speaking countries has some differences compared to Vietnam:</p>\n<ul>\n<li><strong>Credit system:</strong> Students choose their own courses each semester to earn enough credits for graduation.</li>\n<li><strong>Office hours:</strong> Professors set specific times when students can visit for help. <em>\"I\'ll go to the professor\'s office hours to ask about the assignment.\"</em></li>\n<li><strong>Group projects:</strong> Many courses require collaborative work with other students.</li>\n<li><strong>Midterm / Final exams:</strong> Most courses have a midterm exam (giữa kỳ) and a final exam (cuối kỳ).</li>\n<li><strong>GPA:</strong> Grade Point Average on a 4.0 scale. 3.5+ is considered excellent.</li>\n</ul>',1),(43,11,'text','<h3>Useful Phrases for University</h3>\n<ul>\n<li><strong>I\'m majoring in...</strong> - Tôi chuyên ngành...</li>\n<li><strong>What year are you?</strong> - Bạn năm mấy? → <em>I\'m a sophomore (năm 2).</em></li>\n<li><strong>When is the deadline?</strong> - Khi nào hạn nộp?</li>\n<li><strong>Could I get an extension?</strong> - Có thể gia hạn được không?</li>\n<li><strong>I need to drop this class.</strong> - Tôi cần rút khỏi lớp này.</li>\n<li><strong>Let\'s form a study group.</strong> - Hãy lập nhóm học tập.</li>\n</ul>\n<p><strong>Year names:</strong> Freshman (năm 1), Sophomore (năm 2), Junior (năm 3), Senior (năm 4)</p>',2),(44,14,'text','<h3>Internet & Social Media Vocabulary</h3>\n<ul>\n<li><strong>Post</strong> - đăng bài: <em>She posted a photo on Instagram.</em></li>\n<li><strong>Share</strong> - chia sẻ: <em>Can you share this link?</em></li>\n<li><strong>Follow / Unfollow</strong> - theo dõi / bỏ theo dõi</li>\n<li><strong>Like</strong> - thích: <em>The post got 1000 likes.</em></li>\n<li><strong>Comment</strong> - bình luận: <em>Please leave a comment below.</em></li>\n<li><strong>Notification</strong> - thông báo: <em>I turned off notifications.</em></li>\n<li><strong>Stream / Livestream</strong> - phát trực tiếp</li>\n<li><strong>Hashtag (#)</strong> - thẻ tag: <em>Use the hashtag #LearnEnglish.</em></li>\n<li><strong>Influencer</strong> - người có ảnh hưởng trên MXH</li>\n<li><strong>Go viral</strong> - lan truyền rộng rãi: <em>The video went viral overnight.</em></li>\n</ul>',1),(45,14,'text','<h3>Online Safety Tips</h3>\n<ul>\n<li><strong>Don\'t share personal information</strong> like your address or phone number online.</li>\n<li><strong>Use strong passwords</strong> and change them regularly.</li>\n<li><strong>Enable two-factor authentication (2FA)</strong> for important accounts.</li>\n<li><strong>Be careful with links</strong> from unknown sources - they might be phishing scams.</li>\n<li><strong>Think before you post</strong> - once something is online, it\'s hard to delete.</li>\n</ul>\n<p><strong>Key terms:</strong> phishing (lừa đảo), scam (trò lừa), privacy (quyền riêng tư), hacker (tin tặc)</p>',2),(46,17,'text','<h3>Tips for a Healthy Lifestyle</h3>\n<ul>\n<li><strong>Eat a balanced diet</strong> - Ăn uống cân bằng: Include fruits, vegetables, protein, and whole grains.</li>\n<li><strong>Drink plenty of water</strong> - Uống đủ nước: At least 2 liters per day.</li>\n<li><strong>Get enough sleep</strong> - Ngủ đủ giấc: Adults need 7-9 hours per night.</li>\n<li><strong>Exercise regularly</strong> - Tập thể dục đều đặn: At least 30 minutes, 3 times per week.</li>\n<li><strong>Manage stress</strong> - Kiểm soát căng thẳng: Try meditation or deep breathing.</li>\n<li><strong>Avoid junk food</strong> - Tránh đồ ăn vặt: Limit sugar, salt, and processed foods.</li>\n</ul>',1),(47,17,'text','<h3>Dialogue: Giving Health Advice</h3>\n<div class=\"dialogue\">\n<p><strong>A:</strong> I\'ve been feeling really tired lately.</p>\n<p><strong>B:</strong> Are you getting enough sleep?</p>\n<p><strong>A:</strong> Not really. I usually go to bed after midnight.</p>\n<p><strong>B:</strong> That\'s probably the problem. You should try to sleep before 11 PM.</p>\n<p><strong>A:</strong> You\'re right. I also skip breakfast a lot.</p>\n<p><strong>B:</strong> That\'s not good. Breakfast gives you energy for the whole morning. You should eat something healthy like oatmeal or fruit.</p>\n<p><strong>A:</strong> Thanks for the advice. I\'ll try to change my habits.</p>\n</div>',2),(48,18,'text','<h3>Popular Sports & Exercises</h3>\n<ul>\n<li><strong>Running / Jogging</strong> - chạy bộ: <em>I go jogging in the park every morning.</em></li>\n<li><strong>Swimming</strong> - bơi lội: <em>Swimming is a full-body workout.</em></li>\n<li><strong>Cycling</strong> - đạp xe: <em>I cycle to work instead of driving.</em></li>\n<li><strong>Yoga</strong> - yoga: <em>Yoga helps with flexibility and relaxation.</em></li>\n<li><strong>Weight training</strong> - tập tạ: <em>He does weight training three times a week.</em></li>\n<li><strong>Basketball</strong> - bóng rổ</li>\n<li><strong>Football (Soccer)</strong> - bóng đá</li>\n<li><strong>Badminton</strong> - cầu lông</li>\n</ul>',1),(49,18,'text','<h3>At the Gym - Useful Phrases</h3>\n<ul>\n<li><strong>How much does a membership cost?</strong> - Phí thành viên bao nhiêu?</li>\n<li><strong>Where is the changing room?</strong> - Phòng thay đồ ở đâu?</li>\n<li><strong>Can you show me how to use this machine?</strong> - Bạn chỉ tôi cách dùng máy này được không?</li>\n<li><strong>How many reps should I do?</strong> - Tôi nên tập bao nhiêu lần?</li>\n<li><strong>I need a spotter.</strong> - Tôi cần người hỗ trợ.</li>\n</ul>\n<p><strong>Gym vocabulary:</strong> reps (số lần lặp), sets (hiệp), warm up (khởi động), cool down (thả lỏng), personal trainer (huấn luyện viên cá nhân)</p>',2),(50,3,'text','<h3>Rooms in a House</h3>\n<ul>\n<li><strong>Living room</strong> (phòng khách) - We usually watch TV in the living room.</li>\n<li><strong>Bedroom</strong> (phòng ngủ) - I have my own bedroom upstairs.</li>\n<li><strong>Kitchen</strong> (nhà bếp) - My mother cooks in the kitchen every day.</li>\n<li><strong>Bathroom</strong> (phòng tắm) - The bathroom is next to my bedroom.</li>\n<li><strong>Dining room</strong> (phòng ăn) - We have dinner together in the dining room.</li>\n<li><strong>Balcony</strong> (ban công) - I like to sit on the balcony and read books.</li>\n<li><strong>Garage</strong> (nhà để xe) - My father parks his car in the garage.</li>\n</ul>',1),(51,3,'text','<h3>Household Chores</h3>\n<ul>\n<li><strong>Do the laundry</strong> - giặt quần áo</li>\n<li><strong>Wash the dishes</strong> - rửa bát</li>\n<li><strong>Sweep the floor</strong> - quét nhà</li>\n<li><strong>Take out the trash</strong> - đổ rác</li>\n<li><strong>Water the plants</strong> - tưới cây</li>\n<li><strong>Make the bed</strong> - dọn giường</li>\n</ul>\n<h3>Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Mom:</strong> Can you help me with the housework today?</p>\n<p><strong>You:</strong> Sure, Mom! What should I do?</p>\n<p><strong>Mom:</strong> Please wash the dishes and sweep the floor.</p>\n<p><strong>You:</strong> OK. Should I also take out the trash?</p>\n<p><strong>Mom:</strong> Yes, please. Thank you for helping!</p>\n</div>',2),(52,5,'text','<h3>Hotel Check-in Vocabulary</h3>\n<ul>\n<li><strong>Reservation</strong> - đặt phòng: <em>I have a reservation under the name Nguyen.</em></li>\n<li><strong>Single room</strong> - phòng đơn</li>\n<li><strong>Double room</strong> - phòng đôi</li>\n<li><strong>Check-in / Check-out</strong> - nhận phòng / trả phòng</li>\n<li><strong>Room key / Key card</strong> - chìa khóa phòng / thẻ từ</li>\n<li><strong>Front desk / Reception</strong> - quầy lễ tân</li>\n<li><strong>Bellboy</strong> - nhân viên khuân hành lý</li>\n</ul>',1),(53,5,'text','<h3>Check-in Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Receptionist:</strong> Good evening! Welcome to Grand Hotel. How can I help you?</p>\n<p><strong>Guest:</strong> Hello! I have a reservation for two nights. The name is Tran Van Minh.</p>\n<p><strong>Receptionist:</strong> Let me check... Yes, I found it. A double room with breakfast included. May I see your ID or passport, please?</p>\n<p><strong>Guest:</strong> Here you are.</p>\n<p><strong>Receptionist:</strong> Thank you. Your room is 504 on the fifth floor. Here is your key card. Breakfast is served from 6:30 to 9:30 AM in the restaurant on the second floor.</p>\n<p><strong>Guest:</strong> Is there Wi-Fi in the room?</p>\n<p><strong>Receptionist:</strong> Yes, the password is on the card in your room. Enjoy your stay!</p>\n</div>',2),(54,6,'text','<h3>Asking for Directions</h3>\n<ul>\n<li><strong>Excuse me, how do I get to...?</strong> - Xin lỗi, tôi đi đến... bằng cách nào?</li>\n<li><strong>Is it far from here?</strong> - Có xa đây không?</li>\n<li><strong>Turn left / Turn right</strong> - Rẽ trái / Rẽ phải</li>\n<li><strong>Go straight</strong> - Đi thẳng</li>\n<li><strong>It\'s on the corner</strong> - Nó ở góc đường</li>\n<li><strong>It\'s next to / opposite / between</strong> - Nó ở bên cạnh / đối diện / giữa</li>\n<li><strong>Take the first/second left</strong> - Rẽ trái ở ngã rẽ đầu tiên/thứ hai</li>\n</ul>',1),(55,6,'text','<h3>Dialogue</h3>\n<div class=\"dialogue\">\n<p><strong>Tourist:</strong> Excuse me, could you tell me how to get to the nearest bank?</p>\n<p><strong>Local:</strong> Sure! Go straight for about 200 meters, then turn right at the traffic light.</p>\n<p><strong>Tourist:</strong> Turn right at the traffic light. Got it.</p>\n<p><strong>Local:</strong> Then walk past the post office. The bank is on your left, next to a coffee shop.</p>\n<p><strong>Tourist:</strong> How long does it take to walk there?</p>\n<p><strong>Local:</strong> About 5 minutes. You can\'t miss it!</p>\n<p><strong>Tourist:</strong> Thank you so much!</p>\n</div>',2),(56,11,'text','<h3>University Life in English-speaking Countries</h3>\n<p>University life in English-speaking countries has some differences compared to Vietnam:</p>\n<ul>\n<li><strong>Credit system:</strong> Students choose their own courses each semester to earn enough credits for graduation.</li>\n<li><strong>Office hours:</strong> Professors set specific times when students can visit for help. <em>\"I\'ll go to the professor\'s office hours to ask about the assignment.\"</em></li>\n<li><strong>Group projects:</strong> Many courses require collaborative work with other students.</li>\n<li><strong>Midterm / Final exams:</strong> Most courses have a midterm exam (giữa kỳ) and a final exam (cuối kỳ).</li>\n<li><strong>GPA:</strong> Grade Point Average on a 4.0 scale. 3.5+ is considered excellent.</li>\n</ul>',1),(57,11,'text','<h3>Useful Phrases for University</h3>\n<ul>\n<li><strong>I\'m majoring in...</strong> - Tôi chuyên ngành...</li>\n<li><strong>What year are you?</strong> - Bạn năm mấy? → <em>I\'m a sophomore (năm 2).</em></li>\n<li><strong>When is the deadline?</strong> - Khi nào hạn nộp?</li>\n<li><strong>Could I get an extension?</strong> - Có thể gia hạn được không?</li>\n<li><strong>I need to drop this class.</strong> - Tôi cần rút khỏi lớp này.</li>\n<li><strong>Let\'s form a study group.</strong> - Hãy lập nhóm học tập.</li>\n</ul>\n<p><strong>Year names:</strong> Freshman (năm 1), Sophomore (năm 2), Junior (năm 3), Senior (năm 4)</p>',2),(58,14,'text','<h3>Internet & Social Media Vocabulary</h3>\n<ul>\n<li><strong>Post</strong> - đăng bài: <em>She posted a photo on Instagram.</em></li>\n<li><strong>Share</strong> - chia sẻ: <em>Can you share this link?</em></li>\n<li><strong>Follow / Unfollow</strong> - theo dõi / bỏ theo dõi</li>\n<li><strong>Like</strong> - thích: <em>The post got 1000 likes.</em></li>\n<li><strong>Comment</strong> - bình luận: <em>Please leave a comment below.</em></li>\n<li><strong>Notification</strong> - thông báo: <em>I turned off notifications.</em></li>\n<li><strong>Stream / Livestream</strong> - phát trực tiếp</li>\n<li><strong>Hashtag (#)</strong> - thẻ tag: <em>Use the hashtag #LearnEnglish.</em></li>\n<li><strong>Influencer</strong> - người có ảnh hưởng trên MXH</li>\n<li><strong>Go viral</strong> - lan truyền rộng rãi: <em>The video went viral overnight.</em></li>\n</ul>',1),(59,14,'text','<h3>Online Safety Tips</h3>\n<ul>\n<li><strong>Don\'t share personal information</strong> like your address or phone number online.</li>\n<li><strong>Use strong passwords</strong> and change them regularly.</li>\n<li><strong>Enable two-factor authentication (2FA)</strong> for important accounts.</li>\n<li><strong>Be careful with links</strong> from unknown sources - they might be phishing scams.</li>\n<li><strong>Think before you post</strong> - once something is online, it\'s hard to delete.</li>\n</ul>\n<p><strong>Key terms:</strong> phishing (lừa đảo), scam (trò lừa), privacy (quyền riêng tư), hacker (tin tặc)</p>',2),(60,17,'text','<h3>Tips for a Healthy Lifestyle</h3>\n<ul>\n<li><strong>Eat a balanced diet</strong> - Ăn uống cân bằng: Include fruits, vegetables, protein, and whole grains.</li>\n<li><strong>Drink plenty of water</strong> - Uống đủ nước: At least 2 liters per day.</li>\n<li><strong>Get enough sleep</strong> - Ngủ đủ giấc: Adults need 7-9 hours per night.</li>\n<li><strong>Exercise regularly</strong> - Tập thể dục đều đặn: At least 30 minutes, 3 times per week.</li>\n<li><strong>Manage stress</strong> - Kiểm soát căng thẳng: Try meditation or deep breathing.</li>\n<li><strong>Avoid junk food</strong> - Tránh đồ ăn vặt: Limit sugar, salt, and processed foods.</li>\n</ul>',1),(61,17,'text','<h3>Dialogue: Giving Health Advice</h3>\n<div class=\"dialogue\">\n<p><strong>A:</strong> I\'ve been feeling really tired lately.</p>\n<p><strong>B:</strong> Are you getting enough sleep?</p>\n<p><strong>A:</strong> Not really. I usually go to bed after midnight.</p>\n<p><strong>B:</strong> That\'s probably the problem. You should try to sleep before 11 PM.</p>\n<p><strong>A:</strong> You\'re right. I also skip breakfast a lot.</p>\n<p><strong>B:</strong> That\'s not good. Breakfast gives you energy for the whole morning. You should eat something healthy like oatmeal or fruit.</p>\n<p><strong>A:</strong> Thanks for the advice. I\'ll try to change my habits.</p>\n</div>',2),(62,18,'text','<h3>Popular Sports & Exercises</h3>\n<ul>\n<li><strong>Running / Jogging</strong> - chạy bộ: <em>I go jogging in the park every morning.</em></li>\n<li><strong>Swimming</strong> - bơi lội: <em>Swimming is a full-body workout.</em></li>\n<li><strong>Cycling</strong> - đạp xe: <em>I cycle to work instead of driving.</em></li>\n<li><strong>Yoga</strong> - yoga: <em>Yoga helps with flexibility and relaxation.</em></li>\n<li><strong>Weight training</strong> - tập tạ: <em>He does weight training three times a week.</em></li>\n<li><strong>Basketball</strong> - bóng rổ</li>\n<li><strong>Football (Soccer)</strong> - bóng đá</li>\n<li><strong>Badminton</strong> - cầu lông</li>\n</ul>',1),(63,18,'text','<h3>At the Gym - Useful Phrases</h3>\n<ul>\n<li><strong>How much does a membership cost?</strong> - Phí thành viên bao nhiêu?</li>\n<li><strong>Where is the changing room?</strong> - Phòng thay đồ ở đâu?</li>\n<li><strong>Can you show me how to use this machine?</strong> - Bạn chỉ tôi cách dùng máy này được không?</li>\n<li><strong>How many reps should I do?</strong> - Tôi nên tập bao nhiêu lần?</li>\n<li><strong>I need a spotter.</strong> - Tôi cần người hỗ trợ.</li>\n</ul>\n<p><strong>Gym vocabulary:</strong> reps (số lần lặp), sets (hiệp), warm up (khởi động), cool down (thả lỏng), personal trainer (huấn luyện viên cá nhân)</p>',2);
