INSERT INTO `topics` VALUES (1,'Daily Life','daily-life','Từ vựng và hội thoại về cuộc sống hằng ngày: chào hỏi, giới thiệu bản thân, thói quen hằng ngày.',NULL,'beginner',1,1,'2026-03-25 13:33:15'),(2,'Travel & Tourism','travel-tourism','Học tiếng Anh giao tiếp khi đi du lịch: đặt vé, khách sạn, hỏi đường, mua sắm.',NULL,'intermediate',2,1,'2026-03-25 13:33:15'),(3,'Food & Cooking','food-cooking','Từ vựng về đồ ăn, nấu ăn, gọi món tại nhà hàng và công thức nấu ăn.',NULL,'beginner',3,1,'2026-03-25 13:33:15'),(4,'Education','education','Tiếng Anh trong môi trường học tập: lớp học, trường đại học, học online.',NULL,'intermediate',4,1,'2026-03-25 13:33:15'),(5,'Technology','technology','Từ vựng về công nghệ, máy tính, internet và các thuật ngữ IT phổ biến.',NULL,'advanced',5,1,'2026-03-25 13:33:15'),(6,'Health & Fitness','health-fitness','Tiếng Anh về sức khỏe, bệnh viện, tập gym và dinh dưỡng.',NULL,'intermediate',6,1,'2026-03-25 13:33:15');
